PRAGMA defer_foreign_keys = true;

CREATE TABLE audio_new (
  id TEXT NOT NULL CHECK (length(trim(id)) > 0),
  track_slug TEXT NOT NULL,
  name TEXT NOT NULL CHECK (length(trim(name)) > 0),
  type TEXT NOT NULL CHECK (type IN ('note', 'demo', 'live')),
  date TEXT NOT NULL DEFAULT '1970-01-01' CHECK (date GLOB '[0-9][0-9][0-9][0-9]-[0-9][0-9]-[0-9][0-9]'),
  date_descriptor TEXT,
  object_key TEXT NOT NULL CHECK (length(trim(object_key)) > 0),
  original_filename TEXT,
  content_type TEXT,
  created_at TEXT NOT NULL CHECK (length(trim(created_at)) > 0),
  updated_at TEXT NOT NULL CHECK (length(trim(updated_at)) > 0),
  PRIMARY KEY (id),
  UNIQUE (object_key),
  UNIQUE (track_slug, name),
  FOREIGN KEY (track_slug) REFERENCES tracks(slug) ON DELETE CASCADE ON UPDATE CASCADE
);

CREATE TABLE audio_file_map (
  track_slug TEXT NOT NULL,
  legacy_slug TEXT NOT NULL,
  object_key TEXT NOT NULL,
  original_filename TEXT NOT NULL,
  content_type TEXT NOT NULL,
  PRIMARY KEY (track_slug, legacy_slug)
);


  id,
  track_slug,
  name,
  type,
  date,
  date_descriptor,
  object_key,
  original_filename,
  content_type,
  created_at,
  updated_at
)
SELECT
  lower(hex(randomblob(4))) || '-' ||
    lower(hex(randomblob(2))) || '-4' || substr(lower(hex(randomblob(2))), 2) || '-' ||
    substr('89ab', abs(random()) % 4 + 1, 1) || substr(lower(hex(randomblob(2))), 2) || '-' ||
    lower(hex(randomblob(6))) AS id,
  audio.track_slug,
  CASE
    WHEN audio.description IS NULL OR trim(audio.description) = '' THEN audio.type || ' ' || audio.type_version
    ELSE audio.type || ' ' || audio.type_version || ' - ' || trim(audio.description)
  END AS name,
  audio.type,
  COALESCE(audio.date, '1970-01-01') AS date,
  NULLIF(trim(audio.date_override), '') AS date_descriptor,
  audio_file_map.object_key,
  audio_file_map.original_filename,
  audio_file_map.content_type,
  strftime('%Y-%m-%dT%H:%M:%fZ', 'now') AS created_at,
  strftime('%Y-%m-%dT%H:%M:%fZ', 'now') AS updated_at
FROM audio
LEFT JOIN audio_file_map
  ON audio_file_map.track_slug = audio.track_slug
  AND audio_file_map.legacy_slug = audio.slug;

DROP TABLE audio;
ALTER TABLE audio_new RENAME TO audio;
DROP TABLE audio_file_map;

CREATE INDEX idx_audio_track ON audio(track_slug);
CREATE INDEX idx_audio_type ON audio(type);
CREATE INDEX idx_audio_date ON audio(date);
